  Delil(
    id: 'DELIL-0293',
    category: _estetik,
    subcategory: 'Güzellik',
    title: 'Doğadaki Simetri',
    short: 'Doğada mükemmel simetri örnekleri.',
    expanded: 'Kelebek kanatlarından kar tanesine kadar doğada muhteşem simetri görülür. Bu simetri, estetik bir tasarımın delilidir.',
