  Delil(
    id: 'DELIL-0295',
    category: _felsefi,
    subcategory: 'Varlık Felsefesi',
    title: 'Zorunlu Varlığın Biricikliği',
    short: 'Zorunlu varlık tek olmalıdır.',
    expanded: 'Varlığı kendinden olan birden fazla varlık olsaydı çelişki ortaya çıkardı. Bu nedenle zorunlu varlık birdir ve tektir.',
